import React from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom'; // ✅ Add Routes & Route
import Privacy from './Privacy'; // ✅ Correct path

// ...other imports

function App() {
  return (
    <Router>
      <div className="App">
        <Header />
        <Routes>
          <Route path="/" element={
            <>
              <Hero />
              <HeroForm />
              <Services />
              <Stats />
              <Team />
              <WhyChooseUs />
              <TestimonialsSlider />
            </>
          } />
          <Route path="/privacy" element={<Privacy />} />
        </Routes>
        <Footer />
      </div>
    </Router>
  );
}

export default App;
